class LRUCache:
    def __init__(self, capacity):
        self.capacity = capacity
        # Stores key-value pairs
        self.cache = {}
        # Tracks usage order (key -> timestamp/placeholder for relative order)
        # Since dictionary insertion order is preserved in Python 3.7+, 
        # using the dict itself might suffice, but manually tracking LRU helps clarity.
        # We will simulate a usage list/deque by managing keys directly.
        self.order = [] # Stores keys from LRU (index 0) to MRU (end)

    def _move_to_mru(self, key):
        # Move an existing key to the MRU end of the order list
        if key in self.order:
            self.order.remove(key)
            self.order.append(key)

    def get(self, key):
        if key not in self.cache:
            return -1
        # Hit: Update usage order
        self._move_to_mru(key)
        return self.cache[key]

    def put(self, key, value):
        if key in self.cache:
            # Update existing item and move to MRU
            self.cache[key] = value
            self._move_to_mru(key)
        else:
            # New item Check Capacity
            if len(self.cache) >= self.capacity:
                # Evict LRU item (at the start of 'order')
                lru_key = self.order[0]
                del self.cache[lru_key]
                self.order.pop(0)

            # Insert new item
            self.cache[key] = value
            self.order.append(key)

